import React, {useState} from 'react';

function ProjectList({name, desc}){
  return(
      <a className="works-item smooth-leave" href="booklandia.html">
        <div className="picture">
          <div className="content">
            <div className="text">
              <h2>{name}</h2>
              <ul>
                <li>{desc}</li>
              </ul>
            </div>
          </div>
          <img src="img/works/booklandia.png" alt="" />
        </div>
      </a>
  );
}
export default ProjectList
